import { useState } from "react";
import { getPatients, getAppointments } from "../api";
import jsPDF from "jspdf";
import html2canvas from "html2canvas";

export default function Search() {
  const [phone, setPhone] = useState("");
  const [patients, setPatients] = useState([]);
  const [appointments, setAppointments] = useState([]);

  // ================= SEARCH =================
  const handleSearch = async () => {
    const allPatients = await getPatients();
    const allAppointments = await getAppointments();

    const filteredPatients = allPatients.filter(
      (p) => p.phone === phone
    );

    const filteredAppointments = allAppointments.filter((a) =>
      filteredPatients.some((p) => p.id === a.patient_id)
    );

    setPatients(filteredPatients);
    setAppointments(filteredAppointments);
  };

  // ================= PRINT =================
  const handlePrint = () => {
    window.print();
  };

  // ================= PDF =================
  const handleDownloadPDF = async () => {
    const element = document.getElementById("search-results");
    const canvas = await html2canvas(element);
    const imgData = canvas.toDataURL("image/png");

    const pdf = new jsPDF("p", "mm", "a4");
    pdf.addImage(imgData, "PNG", 10, 10, 190, 0);
    pdf.save("search-results.pdf");
  };

  return (
    <div className="p-6">

      {/* HEADER */}
      <h1 className="text-3xl font-bold mb-6">🔎 Search Patients</h1>

      {/* SEARCH BAR */}
      <div className="bg-white p-4 rounded-2xl shadow mb-6 flex gap-3">

        <input
          className="flex-1 border p-2 rounded"
          placeholder="Enter phone number"
          value={phone}
          onChange={(e) => setPhone(e.target.value)}
        />

        <button
          onClick={handleSearch}
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          Search
        </button>

      </div>

      {/* ACTION BUTTONS */}
      <div className="flex gap-3 mb-4">
        <button
          onClick={handlePrint}
          className="bg-gray-800 text-white px-4 py-2 rounded"
        >
          Print
        </button>

        <button
          onClick={handleDownloadPDF}
          className="bg-green-600 text-white px-4 py-2 rounded"
        >
          Download PDF
        </button>
      </div>

      {/* RESULTS */}
      <div id="search-results" className="space-y-6">

        {/* PATIENTS */}
        <div className="bg-white p-4 rounded-2xl shadow">
          <h2 className="text-xl font-semibold mb-3">Patients</h2>

          {patients.length === 0 ? (
            <p className="text-gray-500">No patients found</p>
          ) : (
            patients.map((p) => (
              <div key={p.id} className="border-b py-2">
                <strong>{p.name}</strong> | {p.phone} | Age: {p.age}
              </div>
            ))
          )}
        </div>

        {/* APPOINTMENTS */}
        <div className="bg-white p-4 rounded-2xl shadow">
          <h2 className="text-xl font-semibold mb-3">Appointments</h2>

          {appointments.length === 0 ? (
            <p className="text-gray-500">No appointments found</p>
          ) : (
            appointments.map((a) => (
              <div key={a.id} className="border-b py-2">
                Patient ID: {a.patient_id} |{" "}
                {new Date(a.date).toLocaleString()}
              </div>
            ))
          )}
        </div>

      </div>
    </div>
  );
}
